import{_ as a,W as t,X as r,Y as p,Z as e,a1 as s}from"./framework-a4c02b8f.js";const n="/assets/images/Mt.Fuji.jpeg",i={},c=e("p",null,"2023年4月29日～5月8日，我前往了日本，并主要游于东京、京都、大阪，这也是我第一次出国，遂记录所闻所感。",-1),d=e("figure",null,[e("img",{src:n,alt:"富士山",tabindex:"0",loading:"lazy"}),e("figcaption",null,"富士山")],-1),o=s('<h1 id="物价差异" tabindex="-1"><a class="header-anchor" href="#物价差异" aria-hidden="true">#</a> 物价差异</h1><p>经典环节，先看看价格！</p><p>早就听闻北京、上海、香港、东京里房价最低的是东京，这次来了一看泪目，物价居然和国内差别不是很大！至少比香港便宜。可尔必思138日元即有400多cc！相对的，普通的一瓶矿泉水要约110日元，但是2升装约160日元，可见贵的原来是塑料包装。</p><p>住宿价格由于我是黄金周（既是中国的也是日本的），就没法客观地评价，就不评价了。</p><h1 id="生活文化差异" tabindex="-1"><a class="header-anchor" href="#生活文化差异" aria-hidden="true">#</a> 生活文化差异</h1><p>日本的路面上是没有垃圾桶的。在有垃圾桶的地方（酒店、地铁站等）主要将垃圾分为可燃垃圾和瓶罐垃圾（也就是回收用的，看来贵的确实是塑料！）。这就导致在日本旅行时，垃圾都得随身先存着，等到了有垃圾桶的地方才好扔。听闻在一户建群中，需要每天早上用特别的垃圾袋将垃圾分类装好放在指定的位置，并标上名字。由此可见，日本人对于垃圾的处置还是很有讲究的，相对的，日本的街道上也是非常干净，看不到一点垃圾。</p><p>日本的地铁到站了会播放出这个站特别的声音，比如秋叶原（AKB）站会播放AKB48的恋爱幸运曲奇，而关西的一些站会播放一些日本传统音乐。</p><p>在东京的街道上，我看到过地下偶像的live；在京都塔的小路边，我看到过市民为No Nuke唱民谣游行。这些也是生活文化的一部分差异。</p><p>京都有很强烈的文化气息。房子基本都是低矮的一户建，而不是国内的高高大大的居民楼。京都有非常多的寺庙和神社，而这其中又有着「御朱印」的文化。这是一种在御朱印帖上用毛笔书写并加以朱印盖章的纪念方式，我非常喜欢这种方式，看着神社相关人员现场为你书写这一份御朱印，真是太有仪式感了。</p><p>另外就是酒店基本都是10点退房，换算过来也就是北京时间9点，这也太早了！</p><p>值得一提的是，我在日本见过的所有厕所都是马桶，且都配有智能马桶盖，这还是比较新奇的。</p><h1 id="交通差异" tabindex="-1"><a class="header-anchor" href="#交通差异" aria-hidden="true">#</a> 交通差异</h1><p>日本的铁路由很多家不同公司开办，因此相对来说会有些割裂感，光是JR就分为JREast、JRWest和JRCentral。在导航软件上，你也有可能会看到，一次轨道交通由三种不同的地铁线路组成，但是你又无需换乘。甚至会有前后几节车厢分离开往不同线路的操作。</p><p>虽然很有割裂感，但是还是很方便的，尤其是东京的铁路（关西的相对来说逊色一些，尤其是京都基本都得靠公交）。但是缺点是很贵，即使只坐一站也要约180日元。</p><p>说到这里，为什么我不称呼其为「地铁」呢？因为其实大多是地上铁。</p><p>所有的交通（除了飞机）都不需要安检，包括对应高铁的「新干线」。</p><h1 id="总结" tabindex="-1"><a class="header-anchor" href="#总结" aria-hidden="true">#</a> 总结</h1><p>日本既物价不贵，又能体验到传统文化（京都），又能体验到都市繁华（东京），还能看到自然美景（富士山），是个非常好去处，还想再去，爱来自中国。</p>',18);function h(l,_){return t(),r("div",null,[c,d,p(" more "),o])}const f=a(i,[["render",h],["__file","TravelNotes_Japan.html.vue"]]);export{f as default};
